SELECT COALESCE(
			   (SELECT o.price FROM stock_transactions t
										JOIN orders o ON t.buy_order_id = o.order_id WHERE o.stock_id = #{stockId}
		        ORDER BY t.created_date DESC LIMIT 1),
		       (SELECT publication_price FROM stocks WHERE stock_id = #{stockId})
       )

SELECT order_id FROM orders
WHERE content = #{content} AND student_id = (SELECT id FROM students WHERE student_id = #{studentId}) AND stock_id = #{stockId}
AND state = #{state} AND amount = #{amount} AND price = #{price} ORDER BY created_date DESC LIMIT 1

SELECT o.order_id, o.content, o.price, o.amount, o.state, o.created_date, s.student_id, o.stock_id
FROM orders o
JOIN students s ON o.student_id = s.id
WHERE o.stock_id = #{stockId}
  AND o.state = '대기'
  AND o.content = #{content}
  AND o.price = #{orderPrice}
  AND s.student_id != (SELECT id FROM students WHERE student_id = #{studentId})
ORDER BY created_date ASC
	FOR UPDATE

mapper.update:
UPDATE orders
SET amount = #{amount},
    state = #{state}
WHERE order_id = #{orderId}

UPDATE orders
SET amount = amount - #{amount}
WHERE order_id = #{orderId}
